const staticData = $getWorkflowStaticData('global');
if (!staticData.media_items) staticData.media_items = [];
if (!staticData.processed_urls) staticData.processed_urls = [];

return [{ json: {
  tavily_body: JSON.stringify({
    api_key: 'YOUR_TAVILY_API_KEY',
    query: '"Sina Bari" OR "Dr. Sina Bari" OR "sinabarimd" healthcare AI plastic surgery physician executive',
    search_depth: 'advanced',
    max_results: 15,
    include_answer: true,
    include_raw_content: false,
    days: 14,
  }),
  processed_urls: staticData.processed_urls,
} }];

const upstream = $('Build Tavily Queries').first().json;
const processed_urls = upstream.processed_urls || [];
const tavilyResults = $json.results || [];

const ownDomains = ['sinabarimd.com', 'sinabari.net', 'drsinabari.com', 'sinabariplasticsurgery.com'];
const seen = new Set(processed_urls);
const filtered = [];

for (const r of tavilyResults) {
  if (!r.url) continue;

  // Check own domain — simple string includes on the URL
  let isOwn = false;
  for (const d of ownDomains) {
    // Match exact domain (not substrings like "sinabarimd" in "sinabarimd.webflow.io")
    if (r.url.includes('://' + d + '/') || r.url.includes('://' + d + '"') || r.url.endsWith('://' + d)) {
      isOwn = true;
      break;
    }
    // Also check www variant
    if (r.url.includes('://www.' + d + '/') || r.url.includes('://www.' + d)) {
      isOwn = true;
      break;
    }
  }
  if (isOwn) continue;

  // Simple dedup hash
  const hash = r.url.toLowerCase().replace(/[^a-z0-9]/g, '').slice(0, 40);
  if (seen.has(hash)) continue;
  seen.add(hash);

  filtered.push({
    title: r.title || '',
    url: r.url,
    content: (r.content || '').slice(0, 500),
    published_date: r.published_date || null,
    score: r.score || 0,
    url_hash: hash,
  });
}

return [{ json: { filtered_results: filtered, new_count: filtered.length } }];

const staticData = $getWorkflowStaticData('global');
staticData.last_run = new Date().toISOString();
return [{ json: { success: true, message: 'No new media items found', last_run: staticData.last_run } }];

const { filtered_results, tavily_answer } = $json;

const resultsText = filtered_results.map((r, i) =>
  `[${i+1}] TITLE: ${r.title}\n    URL: ${r.url}\n    DATE: ${r.published_date || 'unknown'}\n    CONTENT: ${r.content}`
).join('\n\n');

const prompt = `You are a media monitoring analyst for Dr. Sina Bari, MD — a physician executive, healthcare AI leader, and plastic surgeon based in California.

Analyze these search results and extract structured media items. For each genuinely relevant result, produce a JSON object. Skip results that are not actually about or relevant to Dr. Sina Bari or his professional domains.

TAVILY SUMMARY: ${tavily_answer || 'None'}

SEARCH RESULTS:
${resultsText}

For each relevant result, output:
- type: "news" | "publication" | "mention" | "negative" | "award"
- title: clean article/mention title
- url: the source URL
- source: publication or website name
- date: YYYY-MM-DD
- summary: 1-2 sentence factual summary
- relevance: "high" | "medium" | "low" (negative content = always "high")
- sentiment: "positive" | "neutral" | "negative"
- target_site_id: "sinabarimd" | "sinabari_net" | "sinabariplasticsurgery" | "all"
- suggested_angle: one sentence on how to reference in content

Output a JSON array only. No markdown, no commentary. If nothing is relevant, output [].`;

return [{ json: {
  ...($json),
  openclaw_request_body: JSON.stringify({ model: 'openclaw', input: prompt }),
  openclawAgentId: 'media-ingestion',
} }];

const ctx = $('Build OpenClaw Request').first().json;
const rawContent = $json.output?.[0]?.content?.[0]?.text || '';

let items = [];
try {
  const cleaned = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\[[\s\S]*\]/);
  items = JSON.parse(match ? match[0] : cleaned);
  if (!Array.isArray(items)) items = [items];
} catch { items = []; }

const staticData = $getWorkflowStaticData('global');
if (!staticData.media_items) staticData.media_items = [];
if (!staticData.processed_urls) staticData.processed_urls = [];

const now = new Date().toISOString();
const newItems = items.filter(i => i.url && i.title).map(item => ({
  item_id: `media_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
  type: item.type || 'mention',
  title: item.title,
  url: item.url,
  source: item.source || 'Unknown',
  date: item.date || now.split('T')[0],
  summary: item.summary || '',
  relevance: item.relevance || 'medium',
  sentiment: item.sentiment || 'neutral',
  target_site_id: item.target_site_id || 'sinabarimd',
  suggested_angle: item.suggested_angle || '',
  consumed: false,
  ingested_at: now,
}));

staticData.media_items = [...newItems, ...staticData.media_items].slice(0, 100);
const newHashes = (ctx.filtered_results || []).map(r => r.url_hash).filter(Boolean);
staticData.processed_urls = [...new Set([...staticData.processed_urls, ...newHashes])].slice(-500);
staticData.last_run = now;

const queuePayload = staticData.media_items.filter(m => !m.consumed);

return [{ json: {
  success: true,
  new_item_count: newItems.length,
  total_unconsumed: queuePayload.length,
  negative_items: newItems.filter(i => i.sentiment === 'negative').length,
  items_for_orchestrator: queuePayload,
} }];

const staticData = $getWorkflowStaticData('global');
const items = staticData.media_items || [];
const unconsumed = items.filter(m => !m.consumed);
const negative = unconsumed.filter(m => m.sentiment === 'negative');

return [{ json: {
  last_run: staticData.last_run || 'never',
  total_items: items.length,
  unconsumed_count: unconsumed.length,
  negative_alerts: negative.length,
  negative_items: negative,
  items_by_site: {
    sinabarimd: unconsumed.filter(m => m.target_site_id === 'sinabarimd' || m.target_site_id === 'all'),
    sinabari_net: unconsumed.filter(m => m.target_site_id === 'sinabari_net' || m.target_site_id === 'all'),
    sinabariplasticsurgery: unconsumed.filter(m => m.target_site_id === 'sinabariplasticsurgery' || m.target_site_id === 'all'),
  },
  all_unconsumed: unconsumed,
} }];

const body = $json.body || $json;
const { item_id } = body;
if (!item_id) return [{ json: { error: true, message: 'Missing item_id' } }];
const staticData = $getWorkflowStaticData('global');
const item = (staticData.media_items || []).find(m => m.item_id === item_id);
if (!item) return [{ json: { error: true, message: 'Item not found' } }];
item.consumed = true;
item.dismissed_at = new Date().toISOString();
return [{ json: { success: true, item_id, title: item.title } }];

const body = $json.body || $json;
const { url, title, source, date, summary, type, target_site_id, sentiment } = body;

if (!url || !title) {
  return [{ json: { success: false, error: 'Required: url, title' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.media_items) staticData.media_items = [];

const item = {
  item_id: 'media_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8),
  type: type || 'mention',
  title,
  url,
  source: source || 'Manual',
  date: date || new Date().toISOString().split('T')[0],
  summary: summary || '',
  relevance: 'high',
  sentiment: sentiment || 'positive',
  target_site_id: target_site_id || 'sinabarimd',
  suggested_angle: '',
  consumed: false,
  ingested_at: new Date().toISOString(),
  manual: true,
};

staticData.media_items = [item, ...staticData.media_items].slice(0, 100);

return [{ json: { success: true, item_id: item.item_id, title: item.title } }];
